import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/updating-fabric.1C0PZ95m.js";import{t as o}from"./chunks/macos-downloads.DCRwPSpe.js";const s=JSON.parse(`{"title":"Updating Fabric","description":"A step by step guide on how to update Fabric.","frontmatter":{"title":"Updating Fabric","description":"A step by step guide on how to update Fabric.","authors":["IMB11","modmuss50"],"files":[]},"headers":[],"relativePath":"1.21.8/players/updating-fabric.md","filePath":"versions/1.21.8/players/updating-fabric.md","lastUpdated":1760721669000}`);var c={name:`1.21.8/players/updating-fabric.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Updating Fabric <a class="header-anchor" href="#h1" aria-label="Permalink to “Updating Fabric”">​</a></h1><p>This guide will walk you through updating Fabric for the Minecraft Launcher.</p><p>For third party launchers, you should consult their documentation.</p><p>Updating Fabric is a very similar process to installing Fabric, so parts of this guide will be the same as the <a href="./installing-fabric">Installing Fabric</a> guide.</p><h2 id="why-should-i-update-fabric-loader" tabindex="-1">Why Should I Update Fabric Loader? <a class="header-anchor" href="#why-should-i-update-fabric-loader" aria-label="Permalink to “Why Should I Update Fabric Loader?”">​</a></h2><p>Newer mods may require a newer version of Fabric Loader to work, so it&#39;s important to keep it up to date to ensure you can use the latest mods.</p><p>This guide only applies for the official Minecraft Launcher. For third party launchers, you should consult their documentation.</p><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Download the Fabric Installer <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Download the Fabric Installer”">​</a></h2><p>You can download the Fabric Installer from the <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">Fabric Website</a>.</p><p>If you use Windows, download the <code>.exe</code> version (<code>Download For Windows</code>), because it doesn&#39;t require Java to be installed on your system. It instead uses Java that came with the official launcher.</p><p>For macOS and Linux, you should download the <code>.jar</code> version. Sometimes, you need to install Java before this step.</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Run the Fabric Installer <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Run the Fabric Installer”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Close Minecraft and the Minecraft Launcher first before running the installer.</p></div><details class="details custom-block"><summary>Information for macOS users</summary><p>On macOS, you may need to right click the <code>.jar</code> file in your downloads directory and click <code>Open</code> to run it.</p><p><img src="/assets/players/installing-fabric/macos-downloads.png" alt="MacOS context menu on Fabric Installer" loading="lazy"></p><p>When asked &quot;Are you sure you want to open it?&quot;, click <code>Open</code> again.</p></details><p>Once you&#39;ve opened the installer, you should see a screen like this:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Fabric Installer with &quot;Install&quot; highlighted" loading="lazy"></p><p>To update Fabric, simply ensure the game version and Loader version is correct then click <code>Install</code>.</p><div class="warning custom-block"><p class="custom-block-title">IMPORTANT</p><p>Make sure to uncheck &#39;Create Profile&#39; when running the installer, otherwise it will create a new profile, which in this case we don&#39;t need.</p></div><h2 id="3-open-the-profile-in-the-minecraft-launcher" tabindex="-1">3. Open the Profile in the Minecraft Launcher <a class="header-anchor" href="#3-open-the-profile-in-the-minecraft-launcher" aria-label="Permalink to “3. Open the Profile in the Minecraft Launcher”">​</a></h2><p>Once the installer has finished, you can open the Minecraft Launcher and go to the <code>Installations</code> tab. You should go to your Fabric profile and open the edit screen.</p><p>Replace the version with the new version of Fabric Loader you just installed, and press <code>Save</code>.</p><p><img src="/assets/players/updating-fabric.png" alt="Updating Fabric Loader version in the Minecraft Launcher" loading="lazy"></p><h2 id="4-you-re-done" tabindex="-1">4. You&#39;re Done! <a class="header-anchor" href="#4-you-re-done" aria-label="Permalink to “4. You&#39;re Done!”">​</a></h2><p>Once you&#39;ve completed the steps you can go back to the <code>Play</code> tab, select the Fabric profile from the dropdown in the bottom left corner and press play!</p><p>If you encounter any issues whilst following this guide, you can ask for help in the <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric Discord</a> in the <code>#player-support</code> channel.</p>`,25)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};